/bin/zsh -lc "node - <<'NODE'
const assert = require('assert');
const { PromiseCache } = require('./src/cache/promiseCache');

(async () => {
  const cache = new PromiseCache();
  let calls = 0;
  const first = cache.get('a', async () => {
    calls += 1;
    throw new Error('temporary');
  });
  const second = cache.get('a', async () => {
    calls += 1;
    return 'should not run';
  });
  assert.strictEqual(first, second);
  await assert.rejects(first, /temporary/);
  assert.strictEqual(calls, 1);

  const retried = await cache.get('a', async () => {
    calls += 1;
    return 'ok';
  });
  assert.strictEqual(retried, 'ok');
  assert.strictEqual(calls, 2);

  const reused = cache.get('a', async () => {
    calls += 1;
    return 'new';
  });
  assert.strictEqual(await reused, 'ok');
  assert.strictEqual(calls, 2);
})();
NODE"

